const EMPTY_LINE: V4Line = { type: 'empty' }

export function getPageLines(page: number): V4Line[] {
  const raw = _d[page]
  if (!raw) return Array(15).fill(EMPTY_LINE)
  return raw.map((s) => {
    if (!s) return EMPTY_LINE
    if (s === 'b') return { type: 'basmallah' }
    if (s[0] === 's') return { type: 'surah', surahId: parseInt(s.slice(1), 10) }
    if (s[0] === 'a') return { type: 'ayah', text: s.slice(2), centered: s[1] === '1' }
    return EMPTY_LINE
  })
}
